="horizontal"    }    for j=0,1 do      if cklist[i + j] ~=nil then        local name=cklist[i + j][1]        local func1=cklist[i + j][2]        local func2=cklist[i + j][3]        if not name then name="未设置" end        rstt=Yunzhu.intcheck(name,func1,func2)        table.insert(tempTable,rstt)       else        table.insert(tempTable,{LinearLayout,          layout_width='match_parent',          layout_weight=1,})      end    end    table.insert(rest,tempTable)  end  return restendendfunction getButtonBG()local selector = luajava.getStateListDrawable()selector:addState({	android.R.attr.state_pressed}, getVerticalBG({0x34000400,0x34000400},15))selector:addState({	-android.R.attr.state_pressed}, getVerticalBG({0xff131313,0xff131313},15))return selectorendbuts={}function Yunzhu.button(txt,func,txtc)if not txt then txt = "未设置" endif not txtc then txtc="#201E1E" endlocal tid="Cbutton"..guid()buts[tid]=luajava.loadlayout(	{		LinearLayout,		layout_width = 'match_parent',		layout_height = "47.5dp", {			LinearLayout,			layout_width = "fill_parent",			layout_height = "40dp",			layout_gravity = "center",			background = getButtonBG(),			padding="10dp",			onClick = function() 			uiadtext('执行了 '..txt.."","#545454")				Yunzhu.controlWater(buts[tid],300)				vibra:vibrate(10)			luajava.newThread(func):start() end,			{				TextView,--id = luajava.newId(tid),				textColor = txtc,				text = txt,				textSize = "16sp",				layout_height = "wrap_content",				layout_width = "fill_parent",				layout_weight=1,			},{ImageView,				src="/storage/emulated/0/余词/图片/heir.png",				layout_height="14dp",				layout_width="14dp",							}		}})return buts[tid]endfunction getButtonBG()local selector = luajava.getStateListDrawable()selector:addState({	android.R.attr.state_pressed}, getVerticalBG({0x34000400,0x34000400},15))selector:addState({	-android.R.attr.state_pressed}, getVerticalBG({0xff131313,0xff131313},15))return selector